# Strings
if ch in ('"', "'"):
    start = col
    quote = ch
    col += 1
    value_chars = []
    while col < len(line) and line[col] != quote:
        if line[col] == "\\":
            col += 1  # advance to the escaped char
            if col < len(line):
                col += 1  # skip the escaped char (don't include it)
        else:
            value_chars.append(line[col])
            col += 1
    if col >= len(line):
        raise TokenizeError(f"Unterminated string", line_num, start + 1)
    col += 1  # skip closing quote
    value = "".join(value_chars)
    tokens.append(Token(TokenType.STRING, value, line_num, start + 1))
    continue
